var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>치명적인 정보 오염 감지.</color>","JPN":"<color=#ff3636>致命的な情報汚染を検知。</color>","ENG":"<color=#ff3636>Critical data corruption detected.</color>","TWN":"<color=#ff3636>感應到致命性的情報污染。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여동력 0.3%. 사고회로 보호를 위해 재기동 절차가 필요합니다.</color>","JPN":"<color=#ff3636>残余エネルギー0.3％。思考回路の保護のため再起動手続きが必要です。</color>","ENG":"<color=#ff3636>Current remaining power is at 0.3%. Reinitialization is required to protect reasoning system.</color>","TWN":"<color=#ff3636>剩餘動能 0.3%。須重新啟動以保護思考迴路。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후우……. 져 버렸네.","JPN":"ふう……負けてしまったわ。","ENG":"Ugh… I lost.","TWN":"呼……我輸了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"음도 못 잡게 따라붙다니, 집요한 점은 상대적으로 덜 귀여운걸.","JPN":"音も出ないように追いつくなんて、執拗なところは相対的に可愛くないわね。","ENG":"You wouldn't even let me play a single note. I can't say I'm a big fan of such persistence.","TWN":"完全不讓我有喘息空間欸，你固執的可愛扣分！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"실컷 침식파에 시달리게 한 주제에 엄살 피우지 마십시오.","JPN":"散々侵食波で追い詰めてきたくせに大げさに言わないでください。","ENG":"You don't get to whine after bombarding me with that much C-Ray.","TWN":"這些侵蝕波都是你釋放的，請不要做賊喊抓賊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 그래도 한 방 먹였다니 기쁘네.","JPN":"フフッ。でも一発は食らわせたみたいで嬉しいわ。","ENG":"Heh. I'm glad I got a few punches in, at least.","TWN":"呵呵～不過這一拳挨得真是痛快～"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"돌아가면 다른 동료들한테 자랑이라도 해야 하나. 비웃음만 사는 거 아닐지 몰라.","JPN":"帰ったら仲間たちに自慢でもしようかしら。嘲笑ばかりされたら困るけど。","ENG":"Should I brag about this to my colleagues when I get back? Maybe I'll just become a laughingstock.","TWN":"我回去要跟同事炫耀一下嗎？但他們應該只會笑我吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"신체 구조가 붕괴하고 있군요. 윌버는 어디 있습니까.","JPN":"身体構造が崩壊していますね。ウィルバーはどこにいますか。","ENG":"Your physical structure is imploding. Where is Wilbur?","TWN":"身體結構正在崩壞中呢。韋爾伯在哪裡？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"옥상에. 지금쯤 헬기가 도착했을 거야.","JPN":"屋上。今頃ヘリが到着したんじゃないかしら。","ENG":"On the rooftop. The helicopter should be just arriving.","TWN":"在屋頂，不過直升機應該已經到了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지금 가면 늦기 전에 아슬아슬하게 시간을 맞출 수 있어.","JPN":"今行けばギリギリ間に合うと思うわ。","ENG":"You can just make it before it's too late if you go there now.","TWN":"現在上去的話，或許還勉強趕得上。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"설득이 통해서 다행이군요. 질문에 대답해 주셔서 감사합니다.","JPN":"説得が通じて幸いですね。質問に答えていただきありがとうございます。","ENG":"I'm glad you can be reasoned with. Thank you for answering my question.","TWN":"幸好溝通有效，謝謝你的回答。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"호라이즌.","JPN":"ホライズン。","ENG":"Horizon.","TWN":"地平線。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네가 지금 사용하고 있는 몸은 말이야, 아주아주 예전에 만들어진 거야.","JPN":"あなたが今使っている体はね、ずっと昔に作られたものよ。","ENG":"That body of yours right now… it was built a long, long time ago.","TWN":"你現在使用的身體，是非常非常久以前製造的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리 같은 그림자 따위가 범접하지 못할, <color=#ffd34c>왕</color>의 보물이지.","JPN":"私たちみたいなシャドウごときじゃ近づけない、<color=#ffd34c>王</color>の宝物。","ENG":"The treasure of <color=#ffd34c>kings</color> that lowly Shadows like us dare not covet.","TWN":"是像我們這種暗影都不敢冒犯的<color=#ffd34c>王</color>的寶物。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전 안 물어 봤습니다.","JPN":"私は質問していません。","ENG":"I didn't ask.","TWN":"我沒問你這個問題。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래. 물어 봤으면 나도 안 말해 줬어. 결국 어떻게 써야 하는지도 모른다는 뜻이니까.","JPN":"そうね。聞かれたなら私も言わなかったわ。それって、どう使えばいいのかもわからないという意味だからね。","ENG":"Right. I wouldn't have told you this if you had asked. That would mean you wouldn't even know how to use it properly.","TWN":"嗯，就算你問我也不會告訴你，因為我也不知道該如何使用它。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만……. 알고 있으면서 왜 쓰지 않은 거야?","JPN":"でも……わかっていながらどうして使わなかったの？","ENG":"So… How come you didn't use it properly, even when you know how?","TWN":"不過……你明明知道，為什麼不使用？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이번 건이 지극히 개인적인 문제이기 때문입니다.","JPN":"今回の件が極めて個人的な問題だからです。","ENG":"Because this case is a purely personal issue for me.","TWN":"因為這次的事件，是單純的個人恩怨。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};